namespace Azure.ResourceManager.Serialization
{
    internal static class ResponseErrorSerialization
    {
        public static JsonSerializerOptions Options { get; } = CreateOptions();

        private static JsonSerializerOptions CreateOptions()
        {
            var options = new JsonSerializerOptions();
            options.Converters.Add(new ResponseErrorConverter());
            return options;
        }

        private sealed class ResponseErrorConverter : JsonConverter<ResponseError>
        {
