// Licensed under the MIT License.

using System.Text.Json;

namespace Azure.ResourceManager.Serialization
{
    internal static class ResponseErrorSerialization
    {
        internal static void Serialize(Utf8JsonWriter writer, ResponseError value)
        {
            writer.WriteStartObject();
            if (value.Code != null)
            {
                writer.WriteString("code"u8, value.Code);
            }
            if (value.Message != null)
            {
                writer.WriteString("message"u8, value.Message);
            }
            writer.WriteEndObject();
        }

        internal static ResponseError Deserialize(JsonElement element)
        {
            string code = null;
            string message = null;
            foreach (var prop in element.EnumerateObject())
            {
                if (prop.NameEquals("code"u8))
                    code = prop.Value.GetString();
                else if (prop.NameEquals("message"u8))
                    message = prop.Value.GetString();
            }
            return new ResponseError(code, message);
        }
    }
}

