// Copyright (c) Microsoft Corporation. All rights reserved.
// Licensed under the MIT License.

using System;
using System.Text.Json;
using System.Text.Json.Serialization;

namespace Azure.ResourceManager.Serialization
{
    internal static class ResponseErrorSerialization
    {
        public static JsonSerializerOptions Options { get; } = CreateOptions();

        private static JsonSerializerOptions CreateOptions()
        {
            var options = new JsonSerializerOptions();
            options.Converters.Add(new ResponseErrorConverter());
            return options;
        }

        private sealed class ResponseErrorConverter : JsonConverter<ResponseError>
        {
            public override ResponseError Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
            {
                string code = null;
                string message = null;
                using var doc = JsonDocument.ParseValue(ref reader);
                foreach (var prop in doc.RootElement.EnumerateObject())
                {
                    if (prop.NameEquals("code"u8))
                        code = prop.Value.GetString();
                    else if (prop.NameEquals("message"u8))
                        message = prop.Value.GetString();
                }
                return new ResponseError(code, message);
            }

            public override void Write(Utf8JsonWriter writer, ResponseError value, JsonSerializerOptions options)
            {
                writer.WriteStartObject();
                if (value.Code != null)
                {
                    writer.WriteString("code"u8, value.Code);
                }
                if (value.Message != null)
                {
                    writer.WriteString("message"u8, value.Message);
                }
                writer.WriteEndObject();
            }
        }
    }
}

